-- Helper: check if a string contains a substring
local function string_contains(str, substr)
    return string.find(str, substr, 1, true) ~= nil
end

-- Helper: check if URI matches any pattern in a list
local function uri_matches_any(uri, patterns)
    for _, pattern in ipairs(patterns) do
        if string_contains(uri, pattern) then
            return true
        end
    end
    return false
end

-- Decode a simple base64-encoded JSON token (simplified for demonstration)
-- In production, use a proper JWT library like lua-resty-jwt
local function decode_token(token)
    if not token or token == "" then
        return nil, "empty token"
    end

    local cjson = require("cjson.safe")

    -- Split token by "." (simulating JWT: header.payload.signature)
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        parts[#parts + 1] = part
    end

    if #parts ~= 3 then
        return nil, "invalid token format"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature = parts[3]

    -- Verify signature using HMAC-SHA256
    local hmac = require("resty.hmac")
    local hmac_sha256 = hmac:new(AUTH_SECRET, hmac.ALGOS.SHA256)
    if not hmac_sha256 then
        return nil, "failed to create HMAC instance"
    end

    local signing_input = header_b64 .. "." .. payload_b64
    local ok = hmac_sha256:update(signing_input)
    if not ok then
        return nil, "failed to update HMAC"
    end

    local digest = hmac_sha256:final()
    local ngx_encode_base64 = ngx.encode_base64
    local expected_signature = ngx_encode_base64(digest)
    -- Make base64 URL-safe
    expected_signature = string.gsub(expected_signature, "+", "-")
    expected_signature = string.gsub(expected_signature, "/", "_")
    expected_signature = string.gsub(expected_signature, "=", "")

    if signature ~= expected_signature then
        return nil, "invalid signature"
    end

    -- Decode payload
    -- Restore standard base64 from URL-safe base64
    local payload_std = string.gsub(payload_b64, "-", "+")
    payload_std = string.gsub(payload_std, "_", "/")
    local padding = 4 - (#payload_std % 4)
    if padding ~= 4 then
        payload_std = payload_std .. string.rep("=", padding)
    end

    local payload_json = ngx.decode_base64(payload_std)
    if not payload_json then
        return nil, "failed to decode payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "failed to parse payload JSON: " .. (err or "unknown error")
    end

    return payload, nil
end

-- Validate token expiration and required fields
local function validate_token_claims(claims)
    if not claims then
        return false, "no claims provided"
    end

    -- Check required fields
    if not claims.sub or claims.sub == "" then
        return false, "missing subject (sub) claim"
    end

    if not claims.role or claims.role == "" then
        return false, "missing role claim"
    end

    -- Check expiration
    if claims.exp then
        local now = ngx.time()
        if now > claims.exp then
            return false, "token has expired"
        end
    else
        return false, "missing expiration (exp) claim"
    end

    -- Check issued-at is not in the future
    if claims.iat then
        local now = ngx.time()
        if claims.iat > now + 60 then  -- allow 60 seconds clock skew
            return false, "token issued in the future"
        end
    end

    return true, nil
end

-- Check if user role has permission to access the given URI
local function check_role_permission(role, uri)
    local permissions = role_permissions[role]
    if not permissions then
        return false, "unknown role: " .. tostring(role)
    end

    for _, allowed_path in ipairs(permissions) do
        -- Check if the request URI starts with or contains the allowed path
        if string_contains(uri, allowed_path) then
            return true, nil
        end
    end

    return false, "insufficient permissions for role '" .. role .. "' to access '" .. uri .. "'"
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri
    local request_method = ngx.req.get_method()

    -- Log the incoming request for debugging
    ngx.log(ngx.DEBUG, "Access control check for URI: ", uri, " Method: ", request_method)

    -- Step 1: Check if the endpoint should skip permission checks
    if uri_matches_any(uri, skip_endpoints) then
        ngx.log(ngx.DEBUG, "Skipping permission check for public endpoint: ", uri)
        return  -- Allow access without authentication
    end

    -- Step 2: Determine if this is a protected endpoint (contains /admin or /api)
    local is_protected = string_contains(uri, "/admin") or string_contains(uri, "/api")

    if not is_protected then
        ngx.log(ngx.DEBUG, "URI does not match /admin or /api, skipping permission check: ", uri)
        return  -- Allow access for non-protected endpoints
    end

    -- Step 3: Extract the authentication token from the Authorization header
    local auth_header = ngx.req.get_headers()["Authorization"]
    if not auth_header then
        ngx.log(ngx.WARN, "Missing Authorization header for protected endpoint: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access"'
        ngx.say('{"error": "unauthorized", "message": "Missing Authorization header"}')
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 4: Parse the Bearer token
    local token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
    if not token then
        ngx.log(ngx.WARN, "Invalid Authorization header format for: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access", error="invalid_token"'
        ngx.say('{"error": "unauthorized", "message": "Invalid Authorization header format. Expected: Bearer <token>"}')
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 5: Decode and validate the token
    local claims, decode_err = decode_token(token)
    if not claims then
        ngx.log(ngx.WARN, "Token decode failed for URI: ", uri, " Error: ", decode_err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error": "unauthorized", "message": "Invalid token: ' .. decode_err .. '"}')
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 6: Validate token claims (expiration, required fields)
    local valid, validation_err = validate_token_claims(claims)
    if not valid then
        ngx.log(ngx.WARN, "Token validation failed for URI: ", uri, " Error: ", validation_err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error": "unauthorized", "message": "Token validation failed: ' .. validation_err .. '"}')
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 7: Check role-based permissions
    local user_role = string.lower(claims.role)
    local has_permission, perm_err = check_role_permission(user_role, uri)

    if not has_permission then
        ngx.log(ngx.WARN, "Permission denied for user: ", claims.sub,
                " role: ", user_role, " URI: ", uri, " Error: ", perm_err)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error": "forbidden", "message": "' .. perm_err .. '"}')
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Step 8: Set upstream headers with user information for downstream services
    ngx.req.set_header("X-User-ID", claims.sub)
    ngx.req.set_header("X-User-Role", user_role)
    if claims.email then
        ngx.req.set_header("X-User-Email", claims.email)
    end

    ngx.log(ngx.INFO, "Access granted for user: ", claims.sub,
            " role: ", user_role, " URI: ", uri)

    -- Access granted, request continues to upstream
end

