    local payload = {
        sub = subject,
        role = role,
        iat = ngx.time(),
        exp = ngx.time() + ttl_seconds
    }

    local function base64url_encode(input)
        local b64 = ngx.encode_base64(input)
        b64 = string.gsub(b64, "+", "-")
        b64 = string.gsub(b64, "/", "_")
        b64 = string.gsub(b64, "=", "")
        return b64
    end

    local header_b64 = base64url_encode(cjson.encode(header))
    local payload_b64 = base64url_encode(cjson.encode(payload))
    local signing_input = header_b64 .. "." .. payload_b64

    local hmac_sha256 = hmac:new(AUTH_SECRET, hmac.ALGOS.SHA256)
    hmac_sha256:update(signing_input)
    local digest = hmac_sha256:final()
    local signature = base64url_encode(digest)

    return signing_input .. "." .. signature
end

